questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values ===== */
N:    if set=1 then 10 else if set=2 then 15 else 8;
r_cm: if set=1 then 5  else if set=2 then 4  else 6;
B0:   if set=1 then 0.2 else if set=2 then 0.15 else 0.25;
f:    if set=1 then 60 else if set=2 then 50 else 100;

/* ===== Derived values ===== */
r_val: r_cm/100;
omega: float(2*%pi*f);
A_val: float(%pi*r_val^2);
peak_emf: float(N*omega*B0*A_val);

/* Display-friendly values */
omega_disp: float(omega);
A_disp: float(A_val);

/* ===== Common-error reference values ===== */
emf_no_omega: float(N*B0*A_val);
emf_no_N: float(omega*B0*A_val);
emf_no_pi: float(N*omega*B0*r_val^2);

/* ===== Teacher answers ===== */
ta1: float(peak_emf);

/* Part (b) MCQ: Direction of induced current (Lenz's law) */
ta2: [[1, true, "Clockwise (when viewed from the direction of B) — opposes the increase in flux"],
      [2, false, "Counterclockwise (when viewed from the direction of B) — aids the increase in flux"],
      [3, false, "No current flows — the coil is open-circuited"],
      [4, false, "The direction depends on the coil resistance"]];
ta2_correct: 1;

/* Part (c) MCQ: Effect of doubling frequency */
ta3: [[1, false, "The peak EMF stays the same (frequency does not affect EMF)"],
      [2, true, "The peak EMF doubles (EMF is proportional to ω)"],
      [3, false, "The peak EMF quadruples (EMF is proportional to ω²)"],
      [4, false, "The peak EMF halves (higher frequency means less time for flux change)"]];
ta3_correct: 2;

/* Part (d) MCQ: Identify the missing factor (debug task) */
/* emf_no_omega = N*B0*A = peak_emf / omega — student forgot omega */
ta4: [[1, true, "The angular frequency ω — they computed N·B₀·πr² instead of N·ω·B₀·πr²"],
      [2, false, "The number of turns N — they computed ω·B₀·πr²"],
      [3, false, "The factor π in the area — they computed N·ω·B₀·r² instead of N·ω·B₀·πr²"],
      [4, false, "The magnetic field B₀ — they forgot to include the field strength"]];
ta4_correct: 1;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
/* Order-of-magnitude check */
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;
/* Common error checks */
prt1_forgot_omega: if (abs(emf_no_omega) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/emf_no_omega - 1) < 0.05) then true else false;
prt1_forgot_N: if (abs(emf_no_N) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/emf_no_N - 1) < 0.05) then true else false;
prt1_forgot_pi: if (abs(emf_no_pi) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/emf_no_pi - 1) < 0.05) then true else false;
